function l(){document.querySelectorAll("a[data-plan]").forEach(e=>{e.addEventListener("click",n=>{n.preventDefault();let o=e.getAttribute("data-plan");if(o==="poutnik"){window.Auth?.isLoggedIn()?window.location.href="profil.html":window.Auth?.toggleModal?.();return}d(o,e)})})}async function d(r,e){if(!window.Auth||!window.Auth.isLoggedIn()){window.Auth?.showToast?.("P\u0159ihl\xE1\u0161en\xED vy\u017Eadov\xE1no","Pro n\xE1kup p\u0159edplatn\xE9ho se pros\xEDm nejd\u0159\xEDve p\u0159ihlaste.","info"),window.Auth?.toggleModal?.();return}let n=e.innerHTML;try{e.disabled=!0,e.classList.add("payment-button--loading"),e.innerHTML='<span class="loading-spinner loading-spinner--payment"></span> P\u0159esm\u011Brov\xE1n\xED...';let o=window.API_CONFIG?.BASE_URL||"/api",s=window.getCSRFToken?await window.getCSRFToken():null,t=await fetch(`${o}/payment/create-checkout-session`,{method:"POST",credentials:"include",headers:{"Content-Type":"application/json",...s&&{"X-CSRF-Token":s}},body:JSON.stringify({planId:r})});if(!t.ok){let i="Nepoda\u0159ilo se vytvo\u0159it platebn\xED relaci";try{i=(await t.json()).error||i}catch{}throw new Error(i)}let a=await t.json();if(a.url)window.location.href=a.url;else throw new Error(a.error||"Nepoda\u0159ilo se vytvo\u0159it platebn\xED relaci")}catch(o){console.error("Payment Error:",o),window.Auth?.showToast?.("Chyba platby",o.message,"error"),e.disabled=!1,e.classList.remove("payment-button--loading"),e.innerHTML=n}}document.addEventListener("DOMContentLoaded",()=>l());
